        // ══════════════════ DATA & API ══════════════════
        let items = [];
        let products = [];
        let isAdmin = false;
        const API_URL = 'http://localhost:3000';

        // Base64 Logo for PDF Export
        const APP_LOGO_BASE64 = 'data:image/png;base64,';

        async function init() {
            try {
                const [itemsRes, prodsRes] = await Promise.all([
                    fetch(API_URL + '/api/items'),
                    fetch(API_URL + '/api/products')
                ]);
                items = await itemsRes.json();
                products = await prodsRes.json();

                renderItems();
                renderProducts();
                updateNavCounts();
                populateAllSelects();
                updateUserCalc();
            } catch (e) {
                console.error("Initialization failed:", e);
                items = [];
                products = [];
            }
        }

        init();

        function updateNavCounts() {
            document.getElementById('nav-item-count').textContent = items.length;
            document.getElementById('nav-prod-count').textContent = products.length;
        }

        function populateAllSelects() {
            populateEstSelect();
            const userSel = document.getElementById('user-product');
            const curUser = userSel.value;
            userSel.innerHTML = '<option value="">— Select Product —</option>' +
                products.map(p => `<option value="${p.id}">${esc(p.name)}</option>`).join('');
            if (curUser) userSel.value = curUser;
        }

        // ══════════════════ AUTH & MODES ══════════════════
        function openAdminPortal() {
            if (isAdmin) {
                // Logout logic
                isAdmin = false;
                document.querySelector('.admin-only').style.display = 'none';
                document.getElementById('admin-toggle-btn').textContent = 'ADMIN PORTAL';
                document.getElementById('admin-toggle-btn').classList.replace('btn-danger', 'btn-ghost');
                showTab('user-calc');
                // alert("Logged out of Admin mode.");
            } else {
                showTab('login');
            }
        }

        function doLogin() {
            const pw = document.getElementById('admin-pw').value;
            if (pw === "admin123") {
                isAdmin = true;
                document.querySelector('.admin-only').style.display = 'block';
                document.getElementById('admin-toggle-btn').textContent = 'Logout';
                document.getElementById('admin-toggle-btn').classList.replace('btn-ghost', 'btn-danger');
                document.getElementById('admin-pw').value = '';
                showTab('items'); // Land on Raw Materials
                // alert("Welcome to the Admin Portal.");
            } else {
                // alert("Incorrect password.");
            }
        }

        // ══════════════════ TABS ══════════════════
        function showTab(t) {
            const tabs = ['user-calc', 'login', 'items', 'products', 'estimate'];

            // Security check
            if (!isAdmin && (t === 'items' || t === 'products' || t === 'estimate')) {
                t = 'login';
            }

            tabs.forEach(x => {
                const el = document.getElementById('tab-' + x);
                if (el) {
                    el.style.display = x === t ? 'block' : 'none';
                    if (x === t) {
                        el.classList.remove('anim');
                        void el.offsetWidth;
                        el.classList.add('anim');
                    }
                }
            });

            tabs.forEach(x => {
                const nav = document.getElementById('nav-' + x);
                if (nav) nav.classList.toggle('active', x === t);
            });

            if (t === 'products') {
                document.getElementById('prod-search').value = '';
                renderProducts('');
            }
            if (t === 'estimate') { populateEstSelect(); updateEstimate(); }
            if (t === 'user-calc') { populateAllSelects(); updateUserCalc(); }
        }

        // ══════════════════ ITEM MASTER ══════════════════
        async function addItem() {
            const name = document.getElementById('item-name').value.trim();
            const price = parseFloat(document.getElementById('item-price').value);
            const unit = document.getElementById('item-unit').value;
            if (!name) return;
            if (isNaN(price) || price < 0) return;

            try {
                const res = await fetch(API_URL + '/api/items', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ name, unit, price })
                });
                if (res.ok) {
                    await init(); // Refresh all
                    document.getElementById('item-name').value = '';
                    document.getElementById('item-price').value = '';
                }
            } catch (e) { }
        }

            async function deleteItem(id) {
                if (!confirm('Remove this ingredient? It will also be removed from all product stages.')) return;
                try {
                    const res = await fetch(`${API_URL}/api/items/${id}`, { method: 'DELETE' });
                    if (res.ok) await init();
                } catch (e) { }
            }

                function renderItems() {
                    const count = items.length;
                    document.getElementById('item-count').textContent = count + ' item' + (count !== 1 ? 's' : '');
                    const tb = document.getElementById('item-tbody');
                    if (!count) {
                        tb.innerHTML = `<tr><td colspan="5" class="empty">No ingredients added yet. Start by adding your first material above.</td></tr>`;
                        return;
                    }
                    tb.innerHTML = items.map((it, i) => `
    <tr>
      <td style="color:#bbb;font-size:12px;width:36px">${i + 1}</td>
      <td><strong style="font-weight:600">${esc(it.name)}</strong></td>
      <td><span class="chip chip-blue">${esc(it.unit)}</span></td>
      <td><strong>Rs. ${parseFloat(it.price).toFixed(2)}</strong></td>
      <td style="width:90px"><button class="btn btn-sm btn-danger" onclick="deleteItem(${it.id})">Remove</button></td>
    </tr>
  `).join('');
                }

                // ══════════════════ PRODUCT MASTER ══════════════════
                async function addProduct() {
                    const name = document.getElementById('prod-name').value.trim();
                    const batch = parseFloat(document.getElementById('prod-batch').value);
                    const desc = document.getElementById('prod-desc').value.trim();
                    if (!name) return;
                    if (isNaN(batch) || batch <= 0) return;

                    try {
                        const res = await fetch(API_URL + '/api/products', {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json' },
                            body: JSON.stringify({ name, batch, desc, stages: [] })
                        });
                        if (res.ok) {
                            await init();
                            document.getElementById('prod-name').value = '';
                            document.getElementById('prod-batch').value = '';
                            document.getElementById('prod-desc').value = '';
                        }
                    } catch (e) { }
                }

                    async function deleteProduct(pid) {
                        if (!confirm('Delete this product and all its stages?')) return;
                        try {
                            const res = await fetch(`${API_URL}/api/products/${pid}`, { method: 'DELETE' });
                            if (res.ok) await init();
                        } catch (e) { }
                    }

                        async function syncProduct(p) {
                            try {
                                const res = await fetch(`${API_URL}/api/products/${p.id}`, {
                                    method: 'PUT',
                                    headers: { 'Content-Type': 'application/json' },
                                    body: JSON.stringify(p)
                                });
                                if (res.ok) {
                                    // Update local reference and re-render
                                    const idx = products.findIndex(x => x.id === p.id);
                                    if (idx !== -1) products[idx] = p;
                                    renderProducts();
                                    updateNavCounts();
                                }
                            } catch (e) { console.error("Sync failed", e); }
                        }

                        function addStage(pid) {
                            const p = products.find(x => x.id === pid);
                            if (!p) return;
                            p.stages.push({ id: Date.now(), name: 'Stage ' + (p.stages.length + 1), items: [] });
                            syncProduct(p);
                        }

                        function renameStage(pid, sid, newName) {
                            const p = products.find(x => x.id === pid); if (!p) return;
                            const s = p.stages.find(x => x.id === sid);
                            if (s && newName.trim()) {
                                s.name = newName.trim();
                                syncProduct(p);
                            }
                        }

                        function deleteStage(pid, sid) {
                            const p = products.find(x => x.id === pid); if (!p) return;
                            if (!confirm('Remove this stage?')) return;
                            p.stages = p.stages.filter(s => s.id !== sid);
                            syncProduct(p);
                        }

                        function addStageItem(pid, sid) {
                            const selEl = document.getElementById('si-sel-' + pid + '-' + sid);
                            const qtyEl = document.getElementById('si-qty-' + pid + '-' + sid);
                            const itemId = parseInt(selEl.value);
                            const qty = parseFloat(qtyEl.value);
                            if (!selEl.value) return;
                            if (isNaN(qty) || qty <= 0) return;
                            const p = products.find(x => x.id === pid);
                            const s = p.stages.find(x => x.id === sid);
                            const existing = s.items.find(x => x.itemId === itemId);
                            if (existing) { existing.qty += qty; } else { s.items.push({ itemId, qty }); }
                            syncProduct(p);
                        }

                        function updateStageItemQty(pid, sid, itemId, val) {
                            const v = parseFloat(val);
                            if (isNaN(v) || v <= 0) return;
                            const p = products.find(x => x.id === pid);
                            const s = p.stages.find(x => x.id === sid);
                            const si = s.items.find(x => x.itemId === itemId);
                            if (si) {
                                si.qty = v;
                                syncProduct(p);
                            }
                        }

                        function removeStageItem(pid, sid, itemId) {
                            const p = products.find(x => x.id === pid);
                            const s = p.stages.find(x => x.id === sid);
                            s.items = s.items.filter(x => x.itemId !== itemId);
                            syncProduct(p);
                        }

                        function renderProducts(query = null) {
                            const el = document.getElementById('prod-list');
                            const searchVal = (query !== null ? query : document.getElementById('prod-search').value).trim().toLowerCase();

                            if (!searchVal) {
                                el.innerHTML = `
                <div class="card" style="border: 2px dashed var(--slate3); background: var(--slate); opacity: 0.8;">
                    <div class="empty-state">
                        <svg viewBox="0 0 40 40" fill="none" stroke="currentColor" stroke-width="1.5"><circle cx="20" cy="20" r="10"/><path d="m28 28-5-5"/></svg>
                        <p style="font-weight: 600;">Search for a product to manage</p>
                        <p style="font-size: 13px; color: var(--muted); margin-top: 4px;">Only the searched product will be displayed here.</p>
                    </div>
                </div>`;
                                return;
                            }

                            const filtered = products.filter(p => p.name.toLowerCase().includes(searchVal));

                            if (!filtered.length) {
                                el.innerHTML = `
                <div class="card">
                    <div class="empty-state">
                        <svg viewBox="0 0 40 40" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M12 28l8-8 8 8M12 12l8 8 8-8"/></svg>
                        <p>No products match "${esc(searchVal)}"</p>
                    </div>
                </div>`;
                                return;
                            }

                            el.innerHTML = filtered.map(p => {
                                const totalIng = p.stages.reduce((a, s) => a + s.items.length, 0);

                                // --- FORMULATION BALANCING LOGIC ---
                                const formulationSum = p.stages.reduce((acc, s) => acc + s.items.reduce((accI, si) => accI + (parseFloat(si.qty) || 0), 0), 0);
                                const isBalanced = Math.abs(formulationSum - p.batch) < 0.001;
                                const diff = p.batch - formulationSum;

                                const statusHTML = isBalanced
                                    ? `<span class="chip chip-brand" style="background:rgba(34,197,94,0.1);color:#16a34a">Balanced</span>`
                                    : `<span class="chip" style="background:rgba(239,68,68,0.1);color:#dc2626">Unbalanced (${diff > 0 ? 'Needs ' + diff.toFixed(3) + 'kg' : 'Over by ' + Math.abs(diff).toFixed(3) + 'kg'})</span>`;

                                const stagesHTML = p.stages.length
                                    ? p.stages.map((s, si) => renderStage(p, s, si)).join('')
                                    : `<div style="font-size:13px;color:#bbb;padding:6px 0 10px;text-align:center">No stages yet — click <strong style="color:var(--brand)">+ Add Stage</strong> to define the mixing process.</div>`;

                                return `
    <div class="prod-card">
      <div class="prod-card-header">
        <div>
          <div class="prod-card-name" style="display:flex;align-items:center;gap:12px">
            <div style="display:flex;align-items:center;gap:8px">
                <div class="prod-dot"></div>
                ${esc(p.name)}
            </div>
            ${statusHTML}
          </div>
          <div class="prod-card-meta">
            <span>Target Batch: <strong>${p.batch} kg</strong></span>
            <span>Current Sum: <strong style="color:${isBalanced ? '#16a34a' : '#dc2626'}">${formulationSum.toFixed(3)} kg</strong></span>
            <span>${p.stages.length} stage${p.stages.length !== 1 ? 's' : ''}</span>
            <span>${totalIng} ingredient${totalIng !== 1 ? 's' : ''}</span>
            ${p.desc ? `<span>${esc(p.desc)}</span>` : ''}
          </div>
        </div>
        <div style="display:flex;gap:8px;flex-wrap:wrap">
          <button class="btn btn-sm btn-ghost" onclick="addStage(${p.id})">+ Add Stage</button>
          <button class="btn btn-sm btn-danger" onclick="deleteProduct(${p.id})">Delete</button>
        </div>
      </div>
      <div class="prod-card-body">
        <div class="stage-wrap">${stagesHTML}</div>
      </div>
    </div>`;
                            }).join('');
                        }

                        function renderStage(p, s, stageIndex) {
                            const itemRowsHTML = s.items.map(si => {
                                const it = items.find(x => x.id === si.itemId);
                                if (!it) return '';
                                return `
    <div class="stage-item-row">
      <div class="stage-item-name">${esc(it.name)}</div>
      <span class="chip chip-blue stage-item-unit">${it.unit}</span>
      <input type="number" value="${si.qty}" min="0.001" step="0.001"
        style="width:90px;height:30px;font-size:12px;border-radius:8px"
        onchange="updateStageItemQty(${p.id},${s.id},${it.id},this.value)">
      <span class="stage-item-rate">@ Rs.${it.price.toFixed(2)}/${it.unit}</span>
      <button class="btn btn-xs btn-danger" onclick="removeStageItem(${p.id},${s.id},${it.id})" style="margin-left:auto">✕</button>
    </div>`;
                            }).join('');

                            const opts = items.map(it => `<option value="${it.id}">${esc(it.name)} (${it.unit})</option>`).join('');

                            return `
  <div class="stage-card" style="margin-bottom:8px">
    <div class="stage-head">
      <div style="display:flex;align-items:center;gap:8px">
        <div class="stage-num">${stageIndex + 1}</div>
        <input class="stage-name-input" type="text" value="${esc(s.name)}"
          onblur="renameStage(${p.id},${s.id},this.value)"
          onkeydown="if(event.key==='Enter')this.blur()">
        <span style="font-size:11px;color:var(--muted)">${s.items.length} raw material${s.items.length !== 1 ? 's' : ''}</span>
      </div>
      <button class="btn btn-xs btn-danger" onclick="deleteStage(${p.id},${s.id})">Remove Stage</button>
    </div>
    <div class="stage-body">
      ${s.items.length ? itemRowsHTML : '<div style="font-size:12px;color:#ccc;text-align:center;padding:4px 0 8px">No ingredients — add below</div>'}
    </div>
    <div class="stage-add">
      <select id="si-sel-${p.id}-${s.id}" style="flex:1;min-width:150px;height:30px;font-size:12px">
        <option value="">— Select Raw Material —</option>${opts}
      </select>
      <input type="number" id="si-qty-${p.id}-${s.id}" placeholder="Qty" min="0.001" step="0.001" style="width:90px;height:30px;font-size:12px">
      <button class="btn btn-sm btn-ghost" onclick="addStageItem(${p.id},${s.id})">+ Add</button>
    </div>
  </div>`;
                        }

                        // ══════════════════ PRICE ESTIMATOR ══════════════════
                        function populateEstSelect() {
                            const sel = document.getElementById('est-product');
                            const cur = sel.value;
                            sel.innerHTML = '<option value="">— Select a product —</option>' +
                                products.map(p => `<option value="${p.id}">${esc(p.name)}</option>`).join('');
                            if (cur) sel.value = cur;
                        }

                        // ══════════════════ USER CALCULATOR LOGIC ══════════════════
                        function updateUserCalc() {
                            const el = document.getElementById('user-calc-output');
                            const pid = parseInt(document.getElementById('user-product').value);
                            const qty = parseFloat(document.getElementById('user-qty').value) || 0;

                            if (!pid || !qty) {
                                el.innerHTML = `
                <div class="card">
                    <div class="empty-state">
                        <svg viewBox="0 0 40 40" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M20 5L5 13v14l15 8 15-8V13L20 5z"/><path d="M20 5v22M5 13l15 8 15-8"/></svg>
                        <p>Select a product and enter target quantity to get the mixing formula.</p>
                    </div>
                </div>`;
                                return;
                            }

                            const p = products.find(x => x.id === pid);
                            if (!p) return;

                            const scale = qty / p.batch;
                            let actualRawSum = 0;

                            const stageSummaries = p.stages.map(s => {
                                const stageItems = s.items.map(si => {
                                    const it = items.find(x => x.id === si.itemId);
                                    if (!it) return null;
                                    const scaledQty = si.qty * scale;
                                    actualRawSum += scaledQty;
                                    return { name: it.name, unit: it.unit, scaledQty };
                                }).filter(Boolean);
                                return { name: s.name, items: stageItems };
                            });

                            const isBalanced = Math.abs(actualRawSum - qty) < 0.001;
                            const balanceDiff = actualRawSum - qty;

                            const stageHTML = stageSummaries.map((ss, i) => {
                                const itemsRows = ss.items.map(it => `
                <tr class="result-sub" style="border-bottom: 1px solid var(--slate2)">
                    <td style="padding: 14px 20px; font-size: 15px; color: var(--ink2); font-weight: 500;">
                        ${esc(it.name)}
                    </td>
                    <td style="text-align: right; padding: 14px 20px; font-size: 16px; font-weight: 800; color: var(--brand-dark);">
                        ${it.scaledQty.toFixed(3)}
                    </td>
                    <td style="width: 80px; padding: 14px 20px; color: var(--muted); font-size: 13px; font-weight: 600;">
                        ${esc(it.unit)}
                    </td>
                </tr>`).join('');

                                return `
                <tr class="result-section">
                    <td colspan="3" style="background: var(--ink); color: #fff; padding: 10px 18px; font-weight: 700; font-size: 14px; border-radius: 6px 6px 0 0;">
                        <span style="opacity: 0.6; margin-right: 8px;">STAGE ${i + 1}</span> ${esc(ss.name).toUpperCase()}
                    </td>
                </tr>
                ${itemsRows}`;
                            }).join('');

                            const adviceHTML = isBalanced ? '' : `
            <div style="margin-top: 15px; padding: 15px; background: rgba(245, 158, 11, 0.1); border-radius: 10px; border: 1px solid rgba(245, 158, 11, 0.2); display: flex; gap: 12px; align-items: flex-start;">
                <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="#d97706" stroke-width="2" style="flex-shrink: 0; margin-top: 2px;">
                    <path d="M10 3v7m0 4h.01M3 17h14a2 2 0 002-2V5a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" stroke-linecap="round"/>
                </svg>
                <div style="font-size: 13px; color: #92400e; line-height: 1.5;">
                    <strong style="display:block; margin-bottom: 2px;">Balance Advisory</strong>
                    The master recipe for this product is unbalanced. Using these quantities will result in <strong>${actualRawSum.toFixed(3)} kg</strong> of raw material, which is ${Math.abs(balanceDiff).toFixed(3)} kg ${balanceDiff > 0 ? 'more' : 'less'} than the target batch weight of ${qty} kg.
                </div>
            </div>`;

                            el.innerHTML = `
            <div class="stats-bar anim" style="background: var(--brand); margin-bottom: 24px; padding: 14px 20px; border-radius: 12px; display: flex; align-items: center; justify-content: space-between;">
                <div style="display: flex; align-items: center; gap: 12px;">
                    <strong style="font-size: 16px;">${esc(p.name)}</strong>
                    <div class="stats-bar-sep" style="background: rgba(255,255,255,0.2); height: 20px;"></div>
                    <span style="opacity: 0.8">Target Yield:</span> <strong style="font-size: 16px;">${qty} kg</strong>
                </div>
                <button class="btn btn-brand" onclick="exportUserPDF()" style="background: #fff; color: var(--brand); border: none; height: 34px;">
                    <svg width="14" height="14" viewBox="0 0 16 16" fill="none" stroke="currentColor" stroke-width="2" style="margin-right: 4px;">
                        <path d="M4 11v2a1 1 0 001 1h6a1 1 0 001-1v-2M8 2v7M5 6l3 3 3-3"/>
                    </svg>
                    Export Operator Sheet
                </button>
            </div>

            <div class="card anim" style="padding: 0; box-shadow: 0 4px 20px rgba(0,0,0,0.05); border-radius: 12px; overflow: hidden;">
                <div class="table-wrap">
                    <table style="border-collapse: separate; border-spacing: 0;">
                        <thead>
                            <tr style="background: var(--slate); border-bottom: 2px solid var(--slate3);">
                                <th style="padding: 14px 20px; font-size: 11px; color: var(--muted); text-transform: uppercase;">Raw Material Name</th>
                                <th style="text-align: right; padding: 14px 20px; font-size: 11px; color: var(--muted); text-transform: uppercase;">Required Qty</th>
                                <th style="padding: 14px 20px; font-size: 11px; color: var(--muted); text-transform: uppercase;">Unit</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${stageHTML || '<tr><td colspan="3" class="empty">No mixing stages found.</td></tr>'}
                            <tr style="background: var(--slate); font-weight: 800; font-size: 15px;">
                                <td style="padding: 18px 20px;">TOTAL MATERIAL INPUT</td>
                                <td style="text-align: right; padding: 18px 20px; color: var(--ink);">${actualRawSum.toFixed(3)}</td>
                                <td style="padding: 18px 20px; color: var(--muted);">kg</td>
                            </tr>
                        </tbody>
                    </table>
                </div>
            </div>
            ${adviceHTML}`;
                        }

                        function exportUserPDF() {
                            const pid = parseInt(document.getElementById('user-product').value);
                            const qty = parseFloat(document.getElementById('user-qty').value) || 0;
                            if (!pid || !qty) return;

                            const p = products.find(x => x.id === pid);
                            if (!p) return;

                            const scale = qty / p.batch;
                            let actualRawSum = 0;
                            const date = new Date().toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
                            const time = new Date().toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });

                            const stageBlocks = p.stages.map((s, i) => {
                                const itemsRows = s.items.map(si => {
                                    const it = items.find(x => x.id === si.itemId);
                                    if (!it) return '';
                                    const scaledQty = si.qty * scale;
                                    actualRawSum += scaledQty;
                                    return `
                    <tr>
                        <td style="padding: 10px 15px; border-bottom: 1px solid #eee;">${esc(it.name)}</td>
                        <td style="padding: 10px 15px; border-bottom: 1px solid #eee; text-align: right; font-weight: 700;">${scaledQty.toFixed(3)}</td>
                        <td style="padding: 10px 15px; border-bottom: 1px solid #eee; color: #666;">${esc(it.unit)}</td>
                    </tr>`;
                                }).join('');

                                return `
                <div style="margin-bottom: 25px; border: 1.5px solid #0f172a; border-radius: 8px; overflow: hidden;">
                    <div style="background: #0f172a; color: #fff; padding: 10px 15px; font-weight: 700; display: flex; justify-content: space-between;">
                        <span>STAGE ${i + 1}: ${esc(s.name).toUpperCase()}</span>
                        <span style="opacity: 0.7; font-size: 11px;">${s.items.length} Raw Materials</span>
                    </div>
                    <table style="width: 100%; border-collapse: collapse;">
                        <thead>
                            <tr style="background: #f8fafc; font-size: 11px; color: #64748b; text-transform: uppercase;">
                                <th style="text-align: left; padding: 8px 15px;">Raw Material</th>
                                <th style="text-align: right; padding: 8px 15px;">Quantity</th>
                                <th style="text-align: left; padding: 8px 15px;">Unit</th>
                            </tr>
                        </thead>
                        <tbody>${itemsRows}</tbody>
                    </table>
                </div>`;
                            }).join('');

                            const isBalanced = Math.abs(actualRawSum - qty) < 0.001;
                            const balanceDiff = actualRawSum - qty;

                            const html = `<!DOCTYPE html>
            <html><head><meta charset="UTF-8">
            <title>Operator Sheet — ${esc(p.name)}</title>
            <style>
                body { font-family: 'Inter', sans-serif; padding: 40px; color: #0f172a; line-height: 1.4; }
                .header { border-bottom: 3px solid #0f172a; padding-bottom: 20px; margin-bottom: 30px; display: flex; justify-content: space-between; align-items: flex-end; }
                .brand { font-weight: 800; font-size: 24px; }
                .meta-box { background: #f1f5f9; padding: 15px 20px; border-radius: 10px; margin-bottom: 30px; display: flex; gap: 40px; }
                .meta-item label { display: block; font-size: 10px; color: #64748b; text-transform: uppercase; margin-bottom: 4px; font-weight: 600; }
                .meta-item span { font-weight: 800; font-size: 18px; }
                .warning-box { background: #fffbeb; border: 1px solid #fef3c7; border-radius: 8px; padding: 15px; margin-bottom: 30px; color: #92400e; font-size: 13px; }
                @media print { .no-print { display: none; } }
            </style></head>
            <body>
                <div class="no-print" style="margin-bottom: 20px; text-align: right;">
                    <button onclick="window.print()" style="padding: 10px 20px; background: #0f172a; color: #fff; border: none; border-radius: 6px; cursor: pointer; font-weight: 600;">Print Operator Sheet</button>
                </div>
                <div class="header">
                    <div>
                        <img src="${APP_LOGO_BASE64}" style="height: 48px; width: auto; margin-bottom: 4px;">
                    </div>
                    <div style="text-align: right; font-size: 12px; color: #64748b;">
                        Generated: ${date} at ${time}<br>
                        <span style="font-size: 10px; font-weight: 800; color: #0f172a; text-transform: uppercase; letter-spacing: 2px;">Operator Batch Sheet</span>
                    </div>
                </div>
                
                <div class="meta-box">
                    <div class="meta-item"><label>Product Name</label><span>${esc(p.name)}</span></div>
                    <div class="meta-item"><label>Target Yield</label><span>${qty} kg</span></div>
                    <div class="meta-item"><label>Total Material Weight</label><span style="color: #0f172a;">${actualRawSum.toFixed(3)} kg</span></div>
                </div>

                ${isBalanced ? '' : `
                <div class="warning-box">
                    <strong>Balance Advisory:</strong> This formulation is currently unbalanced. Theoretical total input material is 
                    <strong>${actualRawSum.toFixed(3)} kg</strong>, which differs from the ${qty} kg target yield.
                </div>`}

                ${stageBlocks}
                <div style="margin-top: 40px; padding-top: 20px; border-top: 1px solid #eee; text-align: center; font-size: 11px; color: #94a3b8;">
                    End of Formulation Sheet — Roalux MixLab v2.1
                </div>
            </body></html>`;

                            const win = window.open('', '_blank');
                            win.document.write(html);
                            win.document.close();
                        }

                        function calcEstimate() {
                            const pid = parseInt(document.getElementById('est-product').value);
                            const qty = parseFloat(document.getElementById('est-qty').value) || 0;
                            const margin = parseFloat(document.getElementById('est-margin').value) || 0;
                            if (!pid || !qty) return null;
                            const p = products.find(x => x.id === pid);
                            if (!p) return null;

                            // Theoretical Yield from Master Formulation
                            let masterTotalWeight = 0;
                            p.stages.forEach(s => s.items.forEach(si => masterTotalWeight += si.qty));

                            // Standard Scaling logic (relative to target yield vs master recipe yield)
                            const masterYield = p.batch || masterTotalWeight || 1;
                            const scale = qty / masterYield;

                            let totalCost = 0;
                            let actualRawSum = 0;

                            const stageSummaries = p.stages.map(s => {
                                let stageCost = 0;
                                const stageItems = s.items.map(si => {
                                    const it = items.find(x => x.id === si.itemId);
                                    if (!it) return null;
                                    const scaledQty = si.qty * scale;
                                    const cost = scaledQty * it.price;
                                    stageCost += cost; totalCost += cost;
                                    actualRawSum += scaledQty;
                                    return { name: it.name, unit: it.unit, origQty: si.qty, scaledQty, price: it.price, cost };
                                }).filter(Boolean);
                                return { name: s.name, cost: stageCost, items: stageItems };
                            });

                            const salePrice = totalCost * (1 + margin / 100);
                            const balanceDiff = actualRawSum - qty;
                            const isBalanced = Math.abs(balanceDiff) < 0.001;

                            return { p, qty, margin, scale, totalCost, salePrice, stageSummaries, isBalanced, actualRawSum, balanceDiff };
                        }

                        function updateEstimate() {
                            const el = document.getElementById('estimate-output');
                            const pdfBtn = document.getElementById('pdf-btn');
                            const d = calcEstimate();
                            if (!d) {
                                el.innerHTML = `
      <div class="card">
        <div class="empty-state">
          <svg viewBox="0 0 40 40" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M5 28l8-8 6 6 10-14"/><circle cx="28" cy="10" r="3"/></svg>
          <p>Select a product to see the cost estimate.</p>
        </div>
      </div>`;
                                pdfBtn.style.display = 'none';
                                return;
                            }
                            pdfBtn.style.display = 'inline-flex';
                            const { p, qty, margin, scale, totalCost, salePrice, stageSummaries, isBalanced, actualRawSum, balanceDiff } = d;

                            const stageRows = stageSummaries.map((ss, i) => {
                                const subRows = ss.items.map(r => `
      <tr class="result-sub">
        <td style="color: var(--ink2); font-weight: 500;">${esc(r.name)}</td>
        <td style="font-weight: 700; color: var(--brand-dark);">${r.scaledQty.toFixed(4)} ${r.unit}</td>
        <td style="color: var(--muted); font-size: 13px;">Rs. ${r.price.toFixed(2)}</td>
        <td style="text-align:right; font-weight: 700;">Rs. ${r.cost.toFixed(2)}</td>
      </tr>`).join('');
                                return `
    <tr class="result-section">
      <td colspan="3" style="background: var(--slate); padding: 8px 16px; font-weight: 700; font-size: 12px; border-radius: 4px;">
        <span style="opacity: 0.6; margin-right: 8px;">STAGE ${i + 1}</span> ${esc(ss.name).toUpperCase()}
      </td>
      <td style="text-align:right; background: var(--slate); font-weight: 700;">Rs. ${ss.cost.toFixed(2)}</td>
    </tr>${subRows}`;
                            }).join('');

                            const adviceHTML = isBalanced ? '' : `
            <div style="margin-top: 15px; padding: 15px; background: rgba(245, 158, 11, 0.1); border-radius: 10px; border: 1px solid rgba(245, 158, 11, 0.2); display: flex; gap: 12px; align-items: flex-start;">
                <svg width="20" height="20" viewBox="0 0 20 20" fill="none" stroke="#d97706" stroke-width="2" style="flex-shrink: 0; margin-top: 2px;">
                    <path d="M10 3v7m0 4h.01M3 17h14a2 2 0 002-2V5a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" stroke-linecap="round"/>
                </svg>
                <div style="font-size: 13px; color: #92400e; line-height: 1.5;">
                    <strong style="display:block; margin-bottom: 2px;">Material Balance Advisory</strong>
                    This product's master recipe is unbalanced. For a target yield of ${qty} kg, the total input materials sum to <strong>${actualRawSum.toFixed(3)} kg</strong>.
                </div>
            </div>`;

                            el.innerHTML = `
  <div class="stats-bar anim" style="background: var(--brand); padding: 12px 20px; border-radius: 12px;">
    <strong>${esc(p.name)}</strong>
    <div class="stats-bar-sep"></div>
    <span>Required</span> <strong>${qty} kg</strong>
    <div class="stats-bar-sep"></div>
    <span>Scale</span> <strong>${scale.toFixed(4)}×</strong>
    <div class="stats-bar-sep"></div>
    <span>Margin</span> <strong>${margin}%</strong>
  </div>

  ${adviceHTML}

  <div class="metrics-row anim">
    <div class="metric-card accent">
      <div class="metric-icon brand">
        <svg viewBox="0 0 17 17" stroke="var(--brand)"><rect x="2" y="2" width="13" height="13" rx="2"/><path d="M5 8.5h7M8.5 5v7"/></svg>
      </div>
      <div class="metric-val">Rs. ${totalCost.toFixed(2)}</div>
      <div class="metric-lbl">Total Material Cost</div>
    </div>
    <div class="metric-card">
      <div class="metric-icon slate">
        <svg viewBox="0 0 17 17" stroke="var(--muted)"><circle cx="8.5" cy="8.5" r="5.5"/><path d="M8.5 6v5M6 8.5h5"/></svg>
      </div>
      <div class="metric-val">Rs. ${qty > 0 ? (totalCost / qty).toFixed(2) : '0.00'}</div>
      <div class="metric-lbl">Cost per kg</div>
    </div>
    <div class="metric-card gold">
      <div class="metric-icon gold">
        <svg viewBox="0 0 17 17" stroke="var(--gold)"><path d="M3 12l3-3 2.5 2.5 5-6.5"/><circle cx="13" cy="4" r="1.5"/></svg>
      </div>
      <div class="metric-val" style="color:var(--brand-dark)">Rs. ${salePrice.toFixed(2)}</div>
      <div class="metric-lbl">Selling Price (${margin}% margin)</div>
    </div>
  </div>

  <div class="card anim">
    <div class="card-header">
      <div class="card-title">
        <div class="card-icon"><svg viewBox="0 0 16 16"><rect x="2" y="4" width="12" height="10" rx="1.5"/><path d="M5 4V3a1 1 0 011-1h4a1 1 0 011 1v1"/></svg></div>
        Stage-wise Breakdown
      </div>
    </div>
    <div class="table-wrap">
      <table>
        <thead>
          <tr>
            <th>Stage / Ingredient</th>
            <th>Quantity</th>
            <th>Rate</th>
            <th style="text-align:right">Cost (Rs.)</th>
          </tr>
        </thead>
        <tbody>
          ${stageRows || '<tr><td colspan="4" class="empty">No stages defined for this product.</td></tr>'}
          <tr class="result-total">
            <td colspan="3">Total Material Cost</td>
            <td style="text-align:right">Rs. ${totalCost.toFixed(2)}</td>
          </tr>
          <tr class="result-margin">
            <td colspan="3">Profit Margin (${margin}%)</td>
            <td style="text-align:right">Rs. ${(salePrice - totalCost).toFixed(2)}</td>
          </tr>
          <tr class="result-sale">
            <td colspan="3">Estimated Selling Price</td>
            <td style="text-align:right">Rs. ${salePrice.toFixed(2)}</td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>`;
                        }

                        // ══════════════════ PDF EXPORT ══════════════════
                        function exportPDF() {
                            const d = calcEstimate();
                            if (!d) return;
                            const { p, qty, margin, scale, totalCost, salePrice, stageSummaries } = d;
                            const date = new Date().toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });
                            const time = new Date().toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });

                            const stageBlocks = stageSummaries.map(ss => {
                                const subRows = ss.items.map(r => `
      <tr style="background:#f9f9f9">
        <td style="padding:6px 12px 6px 30px;color:#555;font-size:12px">${esc(r.name)}</td>
        <td style="padding:6px 12px;color:#555;font-size:12px">${r.scaledQty.toFixed(4)} ${r.unit}</td>
        <td style="padding:6px 12px;color:#555;font-size:12px">Rs. ${r.price.toFixed(2)} / ${r.unit}</td>
        <td style="padding:6px 12px;text-align:right;font-size:12px">Rs. ${r.cost.toFixed(2)}</td>
      </tr>`).join('');
                                return `
    <tr style="background:#eef3f9">
      <td style="padding:8px 12px;font-weight:700;color:#0f1923">${esc(ss.name)}</td>
      <td colspan="2" style="padding:8px 12px;font-size:11px;color:#6b7f96">${ss.items.length} ingredient${ss.items.length !== 1 ? 's' : ''}</td>
      <td style="padding:8px 12px;text-align:right;font-weight:700">Rs. ${ss.cost.toFixed(2)}</td>
    </tr>${subRows}`;
                            }).join('');

                            const itemMasterRows = items.map((it, i) => `
    <tr style="${i % 2 === 0 ? '' : 'background:#f9f9f9'}">
      <td style="padding:6px 10px;color:#aaa;font-size:12px">${i + 1}</td>
      <td style="padding:6px 10px;font-weight:600;font-size:12px">${esc(it.name)}</td>
      <td style="padding:6px 10px;font-size:12px">${it.unit}</td>
      <td style="padding:6px 10px;font-size:12px">Rs. ${it.price.toFixed(2)}</td>
      <td style="padding:6px 10px;color:#666;font-size:12px">${it.cat || '—'}</td>
    </tr>`).join('');

                            const html = `<!DOCTYPE html>
<html lang="en"><head><meta charset="UTF-8">
<title>Price Estimate — ${esc(p.name)} — Roalux MixLab</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=DM+Sans:wght@300;400;500;600&family=Syne:wght@700;800&display=swap" rel="stylesheet">
<style>
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:'DM Sans',Arial,sans-serif;font-size:13px;color:#0f1923;background:#fff}
.page{max-width:780px;margin:0 auto;padding:40px 36px}
.letterhead{display:flex;justify-content:space-between;align-items:flex-end;margin-bottom:28px;padding-bottom:18px;border-bottom:3px solid #0f1923}
.brand{display:flex;align-items:center;gap:10px}
.brand-icon{width:38px;height:38px;background:#00b894;border-radius:10px;display:flex;align-items:center;justify-content:center}
.brand-name{font-family:'Syne',sans-serif;font-size:18px;font-weight:800;color:#0f1923;line-height:1.1}
.brand-name span{color:#00b894}
.brand-sub{font-size:10px;color:#aaa;letter-spacing:1.5px;text-transform:uppercase;margin-top:2px}
.doc-meta{text-align:right}
.doc-meta .doc-type{font-family:'Syne',sans-serif;font-size:20px;font-weight:800;color:#0f1923}
.doc-meta p{font-size:11px;color:#aaa;margin-top:3px}
.meta-grid{display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin-bottom:24px}
.meta-box{background:#f4f7fc;border-radius:8px;padding:10px 12px}
.meta-label{font-size:10px;color:#6b7f96;text-transform:uppercase;letter-spacing:0.5px;font-weight:600;margin-bottom:3px}
.meta-val{font-size:13px;font-weight:700;color:#0f1923}
.summary-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:24px}
.summary-box{border:1.5px solid #e2eaf2;border-radius:10px;padding:14px 16px;text-align:center}
.summary-box.accent{border-color:#00b894}
.summary-val{font-family:'Syne',sans-serif;font-size:20px;font-weight:800;color:#0f1923}
.summary-val.green{color:#00a381}
.summary-lbl{font-size:10px;color:#6b7f96;text-transform:uppercase;letter-spacing:0.5px;margin-top:4px}
.section-title{font-family:'Syne',sans-serif;font-size:13px;font-weight:800;color:#0f1923;margin-bottom:10px;padding-bottom:6px;border-bottom:2px solid #0f1923}
table{width:100%;border-collapse:collapse;margin-bottom:24px}
th{text-align:left;padding:8px 12px;font-size:10px;font-weight:700;color:#6b7f96;text-transform:uppercase;letter-spacing:0.5px;border-bottom:1.5px solid #e2eaf2;background:#f8f9fb}
td{padding:7px 12px;border-bottom:1px solid #f0f0f0}
.total-row td{font-weight:700;border-top:2px solid #c8d6e5!important;padding-top:12px;border-bottom:none}
.margin-row td{color:#555;border-bottom:none}
.sale-row td{font-weight:800;font-size:15px;color:#00a381;border-bottom:none;font-family:'Syne',sans-serif}
.footer{font-size:10px;color:#aaa;text-align:center;margin-top:32px;padding-top:12px;border-top:1px solid #eee;display:flex;justify-content:space-between}
.no-print{margin-bottom:20px;text-align:right}
@media print{.no-print{display:none}body{-webkit-print-color-adjust:exact;print-color-adjust:exact}}
</style></head><body>
<div class="page">
  <div class="no-print">
    <button onclick="window.print()" style="padding:10px 22px;background:#0f1923;color:#fff;border:none;border-radius:8px;cursor:pointer;font-size:13px;font-weight:700;font-family:'DM Sans',sans-serif">
      Print / Save as PDF
    </button>
  </div>

  <div class="letterhead">
    <div class="brand">
      <img src="${APP_LOGO_BASE64}" style="height: 48px; width: auto; margin-bottom: 4px;">
      <div>
        <div class="brand-name">ROALUX <span>MIX</span>LAB</div>
        <div class="brand-sub">Paint Formulation System</div>
      </div>
    </div>
    <div class="doc-meta">
      <div class="doc-type">Price Estimate</div>
      <p>Generated: ${date} at ${time}</p>
    </div>
  </div>

  <div class="meta-grid">
    <div class="meta-box"><div class="meta-label">Product</div><div class="meta-val">${esc(p.name)}</div></div>
    <div class="meta-box"><div class="meta-label">Batch Size</div><div class="meta-val">${p.batch} kg</div></div>
    <div class="meta-box"><div class="meta-label">Required Qty</div><div class="meta-val">${qty} kg</div></div>
    <div class="meta-box"><div class="meta-label">Batch Factor</div><div class="meta-val">${scale.toFixed(4)}×</div></div>
    <div class="meta-box"><div class="meta-label">Margin</div><div class="meta-val">${margin}%</div></div>
  </div>

  <div class="summary-grid">
    <div class="summary-box accent">
      <div class="summary-val">Rs. ${totalCost.toFixed(2)}</div>
      <div class="summary-lbl">Total Material Cost</div>
    </div>
    <div class="summary-box">
      <div class="summary-val">Rs. ${qty > 0 ? (totalCost / qty).toFixed(2) : '0.00'}</div>
      <div class="summary-lbl">Cost per kg</div>
    </div>
    <div class="summary-box">
      <div class="summary-val green">Rs. ${salePrice.toFixed(2)}</div>
      <div class="summary-lbl">Selling Price (${margin}% margin)</div>
    </div>
  </div>

  <div class="section-title">Stage-wise Ingredient Breakdown</div>
  <table>
    <thead><tr><th>Stage / Ingredient</th><th>Quantity</th><th>Rate</th><th style="text-align:right">Cost</th></tr></thead>
    <tbody>
      ${stageBlocks || '<tr><td colspan="4" style="text-align:center;color:#aaa;padding:16px">No stages defined.</td></tr>'}
      <tr class="total-row"><td colspan="3">Total Material Cost</td><td style="text-align:right">Rs. ${totalCost.toFixed(2)}</td></tr>
      <tr class="margin-row"><td colspan="3">Profit Margin (${margin}%)</td><td style="text-align:right">Rs. ${(salePrice - totalCost).toFixed(2)}</td></tr>
      <tr class="sale-row"><td colspan="3">Estimated Selling Price</td><td style="text-align:right">Rs. ${salePrice.toFixed(2)}</td></tr>
    </tbody>
  </table>

  ${items.length ? `
  <div class="section-title">Item Master Reference</div>
  <table>
    <thead><tr><th>#</th><th>Ingredient</th><th>Unit</th><th>Price / Unit</th><th>Category</th></tr></thead>
    <tbody>${itemMasterRows}</tbody>
  </table>` : ''}

  <div class="footer">
    <span>Roalux MixLab — Paint Formulation System</span>
    <span>${esc(p.name)} &bull; ${date}</span>
    <span>Confidential</span>
  </div>
</div></body></html>`;

                            const blob = new Blob([html], { type: 'text/html' });
                            const url = URL.createObjectURL(blob);
                            const win = window.open(url, '_blank');
                            if (win) { win.onload = () => setTimeout(() => win.print(), 400); }
                            else {
                                const a = document.createElement('a');
                                a.href = url;
                                a.download = 'roalux-estimate-' + p.name.replace(/\s+/g, '-').toLowerCase() + '.html';
                                a.click();
                            }
                            setTimeout(() => URL.revokeObjectURL(url), 8000);
                        }

                        // ══════════════════ UTILS ══════════════════
                        function esc(str) {
                            return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
                        }
